#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 508
#endif

#ifndef DEFAULT_ORDER_2
#define DEFAULT_ORDER_2 508
#endif

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

void findK_kernel(
	long height,
	knode *knodesD,
	long knodes_elem,
	record *recordsD,
	long *currKnodeD,
	long *offsetD,
	int *keysD,
	record *ansD,
	int count,
	int order)
{
	#pragma omp parallel for
	for(int bid = 0; bid < count; bid++) {
		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];

		int i;
		for(i = 0; i < height; i++){
			int thid;
			for(thid = 0; thid < order; thid++){
				if((knodesD[currKnode].keys[thid]) <= keysD[bid] && 
				   (knodesD[currKnode].keys[thid+1] > keysD[bid])){
					if(knodesD[offset].indices[thid] < knodes_elem){
						offset = knodesD[offset].indices[thid];
					}
				}
			}
			currKnode = offset;
		}

		int thid;
		for(thid = 0; thid < order; thid++){
			if(knodesD[currKnode].keys[thid] == keysD[bid]){
				ansD[bid].value = recordsD[knodesD[currKnode].indices[thid]].value;
			}
		}
	}
}

void findRangeK_kernel(
	long height,
	knode *knodesD,
	long knodes_elem,
	long *currKnodeD,
	long *offsetD,
	long *lastKnodeD,
	long *offset_2D,
	int *startD,
	int *endD,
	int *RecstartD,
	int *ReclenD,
	int count,
	int order)
{
	#pragma omp parallel for
	for(int bid = 0; bid < count; bid++) {
		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];
		long lastKnode = lastKnodeD[bid];
		long offset_2 = offset_2D[bid];

		int i;
		for(i = 0; i < height; i++){
			int thid;
			for(thid = 0; thid < order; thid++){
				if((knodesD[currKnode].keys[thid] <= startD[bid]) && 
				   (knodesD[currKnode].keys[thid+1] > startD[bid])){
					if(knodesD[currKnode].indices[thid] < knodes_elem){
						offset = knodesD[currKnode].indices[thid];
					}
				}
				if((knodesD[lastKnode].keys[thid] <= endD[bid]) && 
				   (knodesD[lastKnode].keys[thid+1] > endD[bid])){
					if(knodesD[lastKnode].indices[thid] < knodes_elem){
						offset_2 = knodesD[lastKnode].indices[thid];
					}
				}
			}
			currKnode = offset;
			lastKnode = offset_2;
		}

		int thid;
		for(thid = 0; thid < order; thid++){
			if(knodesD[currKnode].keys[thid] == startD[bid]){
				RecstartD[bid] = knodesD[currKnode].indices[thid];
			}
		}

		for(thid = 0; thid < order; thid++){
			if(knodesD[lastKnode].keys[thid] == endD[bid]){
				ReclenD[bid] = knodesD[lastKnode].indices[thid] - RecstartD[bid] + 1;
			}
		}
	}
